import{_ as a,o as t,c as p,j as r,a as b,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"魔力","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/5.能量池/魔力.md","filePath":"4.资源分区/5.能量池/魔力.md"}'),s={name:"4.资源分区/5.能量池/魔力.md"};function o(d,e,l,i,_,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"魔力",tabindex:"-1"},[b("魔力 "),r("a",{class:"header-anchor",href:"#魔力","aria-label":'Permalink to "魔力"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘002A")])])],-1),n('<h1 id="魔力-1" tabindex="-1">魔力 <a class="header-anchor" href="#魔力-1" aria-label="Permalink to &quot;魔力&quot;">​</a></h1><p>魔力<br> 魔力是一种西方通用能量，但若没有特殊说明，则只能驱动需要消耗魔力的相关技艺，而不能作为其他技艺的能耗使用。<br> 魔力分两种类型：精神魔力、生命魔力，此外也有一些异种魔力，这里忽略不计。<br> 精神魔力：关键属性为智力+感知。<br> 生命魔力：关键属性为耐力+风度。</p><p>恢复方式：<br> 1、经过一次完整的长休息后恢复所有魔力<br> 2、经过一次短休息的冥想后恢复关键属性较高者点魔力</p><p>升华仪式<br> 一段经历，一种仪式，总之经历了某种洗礼，从而得到神秘的力量。</p><p>梦境之旅<br> 1000<br> 你需要进行一次平静地沉睡，于梦中前往某个神秘的空间，如梦似幻，也许你在梦中走过了一个迷宫，也许你在梦中与神秘的存在进行了交流，当你醒来，梦中之事大部分都会被忘却，但你能感受到你的体内有了一种神秘的力量。<br> 开启魔力池（精神魔力）。</p><p>启迪之光<br> 500<br> 你需要沐浴在阳光之下，并且周围要有一定数量的植物。用心通过植物感受阳光中传递的生命。经过数小时的冥想后你的体内会出现一种新的力量。<br> 开启魔力池（生命魔力）</p><p>星空之秘<br> D+750<br> 你需要在繁星之夜，站立于高山、高楼之类相对较高的地方，凝视着高悬于天空的生命之星，通过数小时的深度冥想与生命之星进行沟通，星光的沐浴让你获得一种特殊的魔力，魔力（星光魔力），星光魔力的关键属性为 智力、耐力、风度、感知四个属性中选择两个 之后不能更改，这是获得者的意念与星空交流的结果。星光魔力既视为精神魔力也视为生命魔力，可以作为精神魔力或生命魔力使用，可以满足需要精神魔力或生命魔力的前置条件，也可以被精神魔力池或生命魔力池相关的强化所强化。星光魔力的能量池上限根据使用者的最高内在强化等级会增加D5、C10、B15、A20、S25。沐浴星光会使你如同普通的技艺一般能获得属性点。若是在夜晚，并且仰头便可没有阻拦地看到天空，那么在非战斗状态下只需要对繁星进行十五分钟的交流就能完全恢复，这一行为一日只能进行一次。</p><p>知识之泉<br> D+500<br> 前提：具有魔力（精神魔力）、未服用过知识之泉<br> 这是一杯泉水，自然不提供属性点。<br> 饮下一杯知识之泉，你的魔力变得强大且温顺，这让你自身与你施展的所有法术均具有【法破】特性。你的魔力（精神魔力）的能量池上限增加智力*1的数值。并且你获得一种特殊的魔力基础用法，进行施法检定以外的智力属性相关检定时，你可以支付1点魔力，令该检定获得2士气加值。</p><p>生命之泉<br> D+500<br> 前提：具有魔力（生命魔力）、未服用过生命之泉<br> 这是一杯泉水，自然不提供属性点。<br> 饮下一杯生命之泉，自然的力量成为你的助力，这让你每回合第一个法术的魔力消耗降低耐力上方附加成功*1的数值，最低为1。你的魔力（生命魔力）的能量池上限增加耐力*1的数值。并且你获得一种特殊的魔力基础用法，你可以消耗1点魔力，使你在一天内用生命魔力替代身体对饮食/休息/呼吸（使用时三选一，同时只能生效一个）的需要。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const m=a(s,[["render",o]]);export{f as __pageData,m as default};
